/**
 * jKanban — Kanban board library (local build, MIT License)
 * Powered by SortableJS (already included in the project).
 *
 * API compatible with jKanban 1.3.x.
 * Usage:
 *   var kanban = new jKanban({
 *       element: '#myKanban',
 *       gutter: '10px',
 *       widthBoard: '280px',
 *       dragItems: true,
 *       boards: [{ id: 'board-1', title: 'Todo', class: '', item: [{id:'1', title:'Task'}] }],
 *       click: function(el) {},
 *       dropEl: function(el, target, source, sibling) {},
 *       dragEl: function(el, source) {},
 *       dragendEl: function(el) {},
 *       buttonClick: function(el, boardId) {}
 *   });
 */
(function (root, factory) {
    'use strict';
    if (typeof module === 'object' && module.exports) {
        module.exports = factory();
    } else {
        root.jKanban = factory();
    }
}(typeof window !== 'undefined' ? window : this, function () {
    'use strict';

    function jKanban(params) {
        this.element        = params.element || '';
        this.gutter         = params.gutter || '15px';
        this.widthBoard     = params.widthBoard || '280px';
        this.responsive     = params.responsive || '';
        this.dragItems      = params.dragItems !== undefined ? params.dragItems : true;
        this.boards         = params.boards || [];
        this.dragBoards     = params.dragBoards !== undefined ? params.dragBoards : false;
        this.addItemButton  = params.addItemButton !== undefined ? params.addItemButton : false;
        this.buttonContent  = params.buttonContent || '+';

        // Callbacks
        this.click         = params.click || function () {};
        this.context       = params.context || function () {};
        this.dragEl        = params.dragEl || function () {};
        this.dragendEl     = params.dragendEl || function () {};
        this.dropEl        = params.dropEl || function () {};
        this.dragBoard     = params.dragBoard || function () {};
        this.dragendBoard  = params.dragendBoard || function () {};
        this.buttonClick   = params.buttonClick || function () {};

        this.itemHandleOptions = params.itemHandleOptions || {};
        this.boardHandleOptions = params.boardHandleOptions || {};

        this._sortables = [];

        this.init();
    }

    jKanban.prototype.init = function () {
        var self     = this;
        var containerEl = typeof this.element === 'string'
            ? document.querySelector(this.element)
            : this.element;

        if (!containerEl) return;

        // Clear existing content
        containerEl.innerHTML = '';
        containerEl.classList.add('kanban-container');

        // Create boards wrapper
        var wrapper = document.createElement('div');
        wrapper.classList.add('kanban-container-inner');
        containerEl.appendChild(wrapper);

        // Create each board
        this.boards.forEach(function (board) {
            self._createBoard(wrapper, board);
        });

        // Make boards draggable if enabled
        if (this.dragBoards && typeof Sortable !== 'undefined') {
            new Sortable(wrapper, {
                handle: '.kanban-board-header',
                draggable: '.kanban-board',
                animation: 150,
                onEnd: function (evt) {
                    self.dragendBoard(evt.item, evt);
                }
            });
        }
    };

    jKanban.prototype._createBoard = function (wrapper, board) {
        var self = this;

        // Board container
        var boardEl = document.createElement('div');
        boardEl.classList.add('kanban-board');
        boardEl.setAttribute('data-id', board.id);
        boardEl.style.width  = this.widthBoard;
        boardEl.style.marginLeft  = this.gutter;
        boardEl.style.marginRight = this.gutter;
        if (board.class) {
            board.class.split(' ').forEach(function (c) {
                if (c) boardEl.classList.add(c);
            });
        }

        // Header
        var header = document.createElement('header');
        header.classList.add('kanban-board-header');
        if (board.headerClass) {
            board.headerClass.split(' ').forEach(function (c) {
                if (c) header.classList.add(c);
            });
        }
        var titleDiv = document.createElement('div');
        titleDiv.classList.add('kanban-title-board');
        titleDiv.innerHTML = board.title || '';
        header.appendChild(titleDiv);

        if (this.addItemButton) {
            var addBtn = document.createElement('button');
            addBtn.classList.add('kanban-title-button', 'btn', 'btn-sm');
            addBtn.innerHTML = this.buttonContent;
            addBtn.addEventListener('click', function (e) {
                self.buttonClick(this, board.id);
                e.preventDefault();
            });
            header.appendChild(addBtn);
        }

        boardEl.appendChild(header);

        // Drag area
        var dragArea = document.createElement('main');
        dragArea.classList.add('kanban-drag');
        if (board.dragTo) {
            dragArea.setAttribute('data-drag-to', board.dragTo.join(','));
        }
        if (board.bodyClass) {
            board.bodyClass.split(' ').forEach(function (c) {
                if (c) dragArea.classList.add(c);
            });
        }
        boardEl.appendChild(dragArea);

        // Items
        if (board.item && board.item.length) {
            board.item.forEach(function (item) {
                self._createItem(dragArea, item);
            });
        }

        // Footer
        var footer = document.createElement('footer');
        footer.classList.add('kanban-board-footer');
        boardEl.appendChild(footer);

        wrapper.appendChild(boardEl);

        // Make items sortable
        if (this.dragItems && typeof Sortable !== 'undefined') {
            var sortableOptions = {
                group: 'kanban-items',
                draggable: '.kanban-item',
                animation: 150,
                ghostClass: 'kanban-item-ghost',
                chosenClass: 'kanban-item-chosen',
                fallbackOnBody: true,
                swapThreshold: 0.65,
                onStart: function (evt) {
                    self.dragEl(evt.item, evt.from);
                },
                onEnd: function (evt) {
                    self.dragendEl(evt.item);
                    if (evt.from !== evt.to || evt.oldIndex !== evt.newIndex) {
                        self.dropEl(evt.item, evt.to, evt.from, evt.newIndex !== undefined ? evt.to.children[evt.newIndex + 1] || null : null);
                    }
                }
            };

            // Handle options
            if (this.itemHandleOptions && this.itemHandleOptions.enabled) {
                sortableOptions.handle = this.itemHandleOptions.handleClass || '.kanban-item-handle';
            }

            var sortable = new Sortable(dragArea, sortableOptions);
            this._sortables.push(sortable);
        }
    };

    jKanban.prototype._createItem = function (parent, item) {
        var self = this;

        var itemEl = document.createElement('div');
        itemEl.classList.add('kanban-item');
        itemEl.setAttribute('data-eid', item.id || '');
        if (item.class) {
            item.class.split(' ').forEach(function (c) {
                if (c) itemEl.classList.add(c);
            });
        }
        itemEl.innerHTML = item.title || '';

        itemEl.addEventListener('click', function (e) {
            // Don't trigger click if we're in a drag
            if (!itemEl.classList.contains('kanban-item-chosen')) {
                self.click(itemEl);
            }
        });

        itemEl.addEventListener('contextmenu', function (e) {
            self.context(itemEl, e);
        });

        parent.appendChild(itemEl);
        return itemEl;
    };

    // ── Public API ────────────────────────────────────────────────────

    jKanban.prototype.addElement = function (boardId, element) {
        var board = this.findBoard(boardId);
        if (!board) return null;
        var dragArea = board.querySelector('.kanban-drag');
        if (!dragArea) return null;
        return this._createItem(dragArea, element);
    };

    jKanban.prototype.addBoards = function (boards) {
        var self = this;
        var container = typeof this.element === 'string'
            ? document.querySelector(this.element)
            : this.element;
        var wrapper = container ? container.querySelector('.kanban-container-inner') : null;
        if (!wrapper) return;

        boards.forEach(function (board) {
            self._createBoard(wrapper, board);
        });
    };

    jKanban.prototype.removeElement = function (elementId) {
        var el = this.findElement(elementId);
        if (el) el.remove();
        return this;
    };

    jKanban.prototype.removeBoard = function (boardId) {
        var board = this.findBoard(boardId);
        if (board) board.remove();
        return this;
    };

    jKanban.prototype.findBoard = function (boardId) {
        var container = typeof this.element === 'string'
            ? document.querySelector(this.element)
            : this.element;
        if (!container) return null;
        return container.querySelector('[data-id="' + boardId + '"]');
    };

    jKanban.prototype.findElement = function (elementId) {
        var container = typeof this.element === 'string'
            ? document.querySelector(this.element)
            : this.element;
        if (!container) return null;
        return container.querySelector('[data-eid="' + elementId + '"]');
    };

    jKanban.prototype.getBoardElements = function (boardId) {
        var board = this.findBoard(boardId);
        if (!board) return [];
        var dragArea = board.querySelector('.kanban-drag');
        if (!dragArea) return [];
        return Array.prototype.slice.call(dragArea.querySelectorAll('.kanban-item'));
    };

    jKanban.prototype.getParentBoardID = function (el) {
        var board = el.closest('.kanban-board');
        return board ? board.getAttribute('data-id') : null;
    };

    jKanban.prototype.destroy = function () {
        this._sortables.forEach(function (s) { s.destroy(); });
        this._sortables = [];
        var container = typeof this.element === 'string'
            ? document.querySelector(this.element)
            : this.element;
        if (container) container.innerHTML = '';
    };

    return jKanban;
}));
